mapper.select:
SELECT SUBJ_CL_ID, SUBJ_CL_NM, USE_YN, RGTR_ID, LAST_MDFR_ID, REG_DT, MDFCN_DT
FROM SUBJECT_CLASSIFICATION
WHERE SUBJ_CL_ID = #{subjClId}

mapper.update:
UPDATE SUBJECT_CLASSIFICATION
SET USE_YN = 'N', LAST_MDFR_ID = #{lastMdfrId}, MDFCN_DT = SYSDATE
WHERE SUBJ_CL_ID = #{subjClId}

UPDATE SUBJECT
SET USE_YN = 'N', LAST_MDFR_ID = #{lastMdfrId}, MDFCN_DT = SYSDATE
WHERE SUBJ_ID = #{subjId} AND SUBJ_CL_ID = #{subjClId}
